// ============================================================================
// SESSION CREATE V2.3 - Process incoming request with uploaded doc fix
// ============================================================================

const body = $input.first().json.body || {};

console.log("=== SESSION CREATE REQUEST V2.3 ===");
console.log("Request body:", JSON.stringify(body, null, 2));

const userEmail = body.userEmail || body.email || "";
const companyName = body.companyName || body.company || "Unknown Company";
const userName = body.userName || body.name || "Unknown User";
const isTraining = body.isTraining === true;

// Assessment fields
const mediationType =
  body.mediation_type || body.mediationType || "full_mediation";
const contractType = body.contract_type || body.contractType || null;
const templateSource =
  body.template_source || body.templateSource || "from_scratch";
const sourceTemplateId =
  body.source_template_id || body.sourceTemplateId || null;
const assessmentCompleted =
  body.assessment_completed ?? body.assessmentCompleted ?? false;

// V2.2: Pathway tracking
const pathwayId = body.pathway_id || body.pathwayId || null;

// V2.3 CRITICAL: Uploaded contract reference (for 'uploaded' template source)
// This is the EXISTING contract_id from document upload, NOT a new one
const uploadedContractId =
  body.uploaded_contract_id || body.uploadedContractId || null;

// Contract name for template-based sessions
const contractName = body.contract_name || body.contractName || null;
// ROLE MATRIX: Contract type key and initiator party role
const contractTypeKey = body.contract_type_key || body.contractTypeKey || null;
const initiatorPartyRole =
  body.initiator_party_role || body.initiatorPartyRole || null;

// Deal context
const dealContext = body.deal_context || body.dealContext || {};
const dealValue = dealContext.deal_value || dealContext.dealValue || null;
const serviceCriticality =
  dealContext.service_criticality || dealContext.serviceCriticality || null;
const timelinePressure =
  dealContext.timeline_pressure || dealContext.timelinePressure || null;
const bidderCount = dealContext.bidder_count || dealContext.bidderCount || null;
const batnaStatus = dealContext.batna_status || dealContext.batnaStatus || null;
const topPriorities =
  dealContext.top_priorities || dealContext.topPriorities || [];

if (!userEmail) {
  return [
    {
      json: {
        error: true,
        message: "User email is required to create a session",
      },
    },
  ];
}

// V2.3: Validate uploaded contract ID is provided for 'uploaded' source
if (templateSource === "uploaded" && !uploadedContractId) {
  console.warn(
    "WARNING: template_source is 'uploaded' but no uploaded_contract_id provided",
  );
}

const now = new Date();
const day = String(now.getDate()).padStart(2, "0");
const month = String(now.getMonth() + 1).padStart(2, "0");
const year = now.getFullYear();
const prefix = isTraining ? "TRN" : "SIS";
const sessionNumberBase = `${prefix}-${day}${month}${year}`;

console.log("Template Source:", templateSource);
console.log("Source Template ID:", sourceTemplateId);
console.log("Uploaded Contract ID:", uploadedContractId);
console.log("Pathway ID:", pathwayId);
console.log("Contract Name:", contractName);

return [
  {
    json: {
      error: false,
      userEmail,
      companyName,
      userName,
      sessionNumberBase,
      isTraining,
      mediationType,
      contractType,
      templateSource,
      sourceTemplateId,
      uploadedContractId,
      pathwayId,
      assessmentCompleted,
      contractName,
      contractTypeKey,
      initiatorPartyRole,
      dealContext: {
        dealValue,
        serviceCriticality,
        timelinePressure,
        bidderCount,
        batnaStatus,
        topPriorities,
      },
      timestamp: now.toISOString(),
    },
  },
];

// V2.3: Added uploadedContractId pass-through
const prevData = $("Process Request").first().json;
const userResult = $input.first().json;

if (!userResult || !userResult.user_id) {
  return [
    {
      json: {
        error: true,
        message: `User not found with email: ${prevData.userEmail}`,
      },
    },
  ];
}

return [
  {
    json: {
      error: false,
      userId: userResult.user_id,
      userEmail: prevData.userEmail,
      companyName: prevData.companyName || userResult.company_name,
      userName: prevData.userName,
      sessionNumberBase: prevData.sessionNumberBase,
      isTraining: prevData.isTraining,
      mediationType: prevData.mediationType,
      contractType: prevData.contractType,
      templateSource: prevData.templateSource,
      sourceTemplateId: prevData.sourceTemplateId,
      uploadedContractId: prevData.uploadedContractId,
      pathwayId: prevData.pathwayId,
      assessmentCompleted: prevData.assessmentCompleted,
      contractName: prevData.contractName,
      contractTypeKey: prevData.contractTypeKey,
      initiatorPartyRole: prevData.initiatorPartyRole,
      dealContext: prevData.dealContext,
      timestamp: prevData.timestamp,
    },
  },
];

const prevData = $('Validate User').first().json;
const sequenceResult = $input.first().json;
const nextSequence = sequenceResult.next_sequence || 101;
const sessionNumber = `${prevData.sessionNumberBase}-${nextSequence}`;

console.log('Final session number:', sessionNumber);
console.log('Pathway ID:', prevData.pathwayId);
console.log('Uploaded Contract ID:', prevData.uploadedContractId);

return [{ json: { ...prevData, sessionNumber, sequenceNumber: nextSequence } }];

// V2.3: Format response for UPLOADED document flow
// Uses the EXISTING contract that was already parsed
const sessionResult = $('Insert Session').first().json;
const requirementsResult = $('Insert Customer Requirements').first().json;
const contractResult = $input.first().json;
const requestData = $('Build Session Number').first().json;

const isTraining = sessionResult.is_training || false;
const pathwayId = sessionResult.pathway_id || null;

let nextStep, nextUrl;

if (isTraining) {
  nextStep = "Start training session";
  nextUrl = `/training/${sessionResult.session_id}`;
} else {
  nextStep = "Configure contract in Contract Prep";
  nextUrl = `/auth/contract-prep?session_id=${sessionResult.session_id}&contract_id=${contractResult.contract_id}&pathway_id=${pathwayId || ''}`;
}

console.log('Uploaded contract linked:', contractResult.contract_id);
console.log('Clause count from existing upload:', contractResult.clause_count);

return [{
  json: {
    success: true,
    message: "Contract session created with uploaded document",
    sessionId: sessionResult.session_id,
    sessionNumber: sessionResult.session_number,
    customerCompany: sessionResult.customer_company,
    status: sessionResult.status,
    isTraining: isTraining,
    mediationType: sessionResult.mediation_type,
    contractType: sessionResult.contract_type,
    templateSource: sessionResult.template_source,
    templateAccepted: false,
    pathwayId: pathwayId,
    // V2.3: Contract info from EXISTING uploaded document
    contractId: contractResult.contract_id,
    contractName: contractResult.contract_name,
    clauseCount: contractResult.clause_count || 0,
    contractStatus: contractResult.status,
    requirementId: requirementsResult?.requirement_id || null,
    createdAt: sessionResult.created_at,
    nextStep: nextStep,
    nextUrl: nextUrl
  }
}];

// V2.3: Format response WITH contractId and pathwayId for template flows
const sessionResult = $('Insert Session').first().json;
const requirementsResult = $('Insert Customer Requirements').first().json;
const contractResult = $('Create Uploaded Contract').first().json;
const clauseCountResult = $input.first().json;

const isTraining = sessionResult.is_training || false;
const pathwayId = sessionResult.pathway_id || null;

let nextStep, nextUrl;

if (isTraining) {
  nextStep = "Start training session";
  nextUrl = `/training/${sessionResult.session_id}`;
} else {
  nextStep = "Configure contract in Contract Prep";
  nextUrl = `/auth/contract-prep?session_id=${sessionResult.session_id}&contract_id=${contractResult.contract_id}&pathway_id=${pathwayId || ''}`;
}

return [{
  json: {
    success: true,
    message: "Contract session created with template",
    sessionId: sessionResult.session_id,
    sessionNumber: sessionResult.session_number,
    customerCompany: sessionResult.customer_company,
    status: sessionResult.status,
    isTraining: isTraining,
    mediationType: sessionResult.mediation_type,
    contractType: sessionResult.contract_type,
    templateSource: sessionResult.template_source,
    templateAccepted: sessionResult.template_accepted,
    pathwayId: pathwayId,
    contractId: contractResult.contract_id,
    contractName: contractResult.contract_name,
    clauseCount: clauseCountResult.clause_count,
    requirementId: requirementsResult?.requirement_id || null,
    createdAt: sessionResult.created_at,
    nextStep: nextStep,
    nextUrl: nextUrl
  }
}];

// V2.3: Format response for from_scratch (no contract yet)
const sessionResult = $('Insert Session').first().json;
const requirementsResult = $('Insert Customer Requirements').first().json;
const requestData = $('Build Session Number').first().json;

const isTraining = sessionResult.is_training || false;
const pathwayId = sessionResult.pathway_id || null;

let nextStep, nextUrl;

if (isTraining) {
  nextStep = "Start training session";
  nextUrl = `/training/${sessionResult.session_id}`;
} else {
  nextStep = "Build contract from scratch";
  let url = `/auth/contract-prep?session_id=${sessionResult.session_id}`;
  if (pathwayId) url += `&pathway_id=${pathwayId}`;
  nextUrl = url;
}

return [{
  json: {
    success: true,
    message: "Contract session created - ready to build from scratch",
    sessionId: sessionResult.session_id,
    sessionNumber: sessionResult.session_number,
    customerCompany: sessionResult.customer_company,
    status: sessionResult.status,
    isTraining: isTraining,
    mediationType: sessionResult.mediation_type,
    contractType: sessionResult.contract_type,
    templateSource: sessionResult.template_source,
    templateAccepted: false,
    pathwayId: pathwayId,
    contractId: null,
    requirementId: requirementsResult?.requirement_id || null,
    createdAt: sessionResult.created_at,
    nextStep: nextStep,
    nextUrl: nextUrl
  }
}];
